#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long W, L; scanf("%lld %lld", &W, &L);
        if((W & 1LL) == 0 || (L & 1LL) == 0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

